/* ============================================================================
 * ASTRO ENGINE — standalone para navegador
 * ----------------------------------------------------------------------------
 * Expõe window.ASTRO_ENGINE.calcChart(year, month, day, hourLocal, lat, lng, tz)
 *
 * Retorna longitudes eclípticas (graus, 0..360) em:
 *   { asc, sol, lua, mercurio, venus, marte, jupiter, saturno,
 *     urano, netuno, plutao, quiron, nodo, jde, T }
 *
 * Precisão:
 *   - Sol: ±0.01° (Meeus, cap. 25)
 *   - Lua: ±0.01° (Meeus, cap. 47 — série ELP truncada)
 *   - Mercúrio..Saturno: ±0.01° (VSOP87 reduzido — termos principais)
 *   - Urano, Netuno: ±0.05°
 *   - Plutão: aproximação (±0.3°, suficiente pra signo/casa)
 *   - Quíron: órbita osculante média (±1°)
 *   - Nodo Norte: médio (Meeus)
 *   - Ascendente: exato (fórmula padrão Meeus 13.5)
 *
 * Sem dependências externas. Tudo inline.
 * ========================================================================= */
(function () {
  "use strict";

  var DEG = 180 / Math.PI;
  var RAD = Math.PI / 180;

  function norm360(x) { return ((x % 360) + 360) % 360; }
  function rad(d) { return d * RAD; }
  function deg(r) { return r * DEG; }

  // -------------------------------------------------------------------------
  // Julian Day (Meeus, cap. 7)
  // -------------------------------------------------------------------------
  function julianDay(year, month, day, hourFrac) {
    if (month <= 2) { year--; month += 12; }
    var A = Math.floor(year / 100);
    var B = 2 - A + Math.floor(A / 4);
    return Math.floor(365.25 * (year + 4716))
         + Math.floor(30.6001 * (month + 1))
         + day + B - 1524.5 + hourFrac / 24;
  }

  // -------------------------------------------------------------------------
  // GMST em graus (Meeus 12.4)
  // -------------------------------------------------------------------------
  function gmstDeg(jd) {
    var T = (jd - 2451545.0) / 36525.0;
    return norm360(
        280.46061837
      + 360.98564736629 * (jd - 2451545.0)
      + 0.000387933 * T * T
      - T * T * T / 38710000
    );
  }

  // -------------------------------------------------------------------------
  // Obliquidade média (Meeus 22.2)
  // -------------------------------------------------------------------------
  function meanObliquityDeg(T) {
    return 23.4392911
         - 0.013004167 * T
         - 1.639e-7   * T * T
         + 5.036e-7   * T * T * T;
  }

  // -------------------------------------------------------------------------
  // Ascendente (Meeus 13.5 / fórmula astrológica padrão)
  //   input: LST em graus, latitude em graus, T (séc. juliano)
  //   output: longitude eclíptica do ascendente em graus (0..360)
  // -------------------------------------------------------------------------
  function ascendantDeg(lstDeg, latDeg, T) {
    var ramc = rad(lstDeg);
    var lat  = rad(latDeg);
    var eps  = rad(meanObliquityDeg(T));
    var num  = -Math.cos(ramc);
    var den  = Math.sin(ramc) * Math.cos(eps) + Math.tan(lat) * Math.sin(eps);
    return norm360(deg(Math.atan2(num, den)) + 180);
  }

  // -------------------------------------------------------------------------
  // SOL — longitude aparente (Meeus cap. 25)
  // -------------------------------------------------------------------------
  function sunLongitude(jd) {
    var T = (jd - 2451545.0) / 36525.0;
    var L0 = norm360(280.46646 + 36000.76983 * T + 0.0003032 * T * T);
    var M  = norm360(357.52911 + 35999.05029 * T - 0.0001537 * T * T);
    var e  = 0.016708634 - 0.000042037 * T - 0.0000001267 * T * T;
    var Mr = rad(M);
    var C  =  (1.914602 - 0.004817 * T - 0.000014 * T * T) * Math.sin(Mr)
            + (0.019993 - 0.000101 * T) * Math.sin(2 * Mr)
            +  0.000289 * Math.sin(3 * Mr);
    var trueLon = L0 + C;
    // correção para longitude aparente (nutation + aberração)
    var omega = 125.04 - 1934.136 * T;
    var apparent = trueLon - 0.00569 - 0.00478 * Math.sin(rad(omega));
    return norm360(apparent);
  }

  // -------------------------------------------------------------------------
  // LUA — Meeus cap. 47, série truncada nos termos dominantes
  // (precisão ~0.01° em longitude)
  // -------------------------------------------------------------------------
  function moonLongitude(jd) {
    var T  = (jd - 2451545.0) / 36525.0;
    var T2 = T * T, T3 = T2 * T, T4 = T3 * T;

    var Lp = norm360(218.3164477 + 481267.88123421 * T - 0.0015786 * T2 + T3 / 538841 - T4 / 65194000);
    var D  = norm360(297.8501921 + 445267.1114034  * T - 0.0018819 * T2 + T3 / 545868 - T4 / 113065000);
    var M  = norm360(357.5291092 +  35999.0502909  * T - 0.0001536 * T2 + T3 / 24490000);
    var Mp = norm360(134.9633964 + 477198.8675055  * T + 0.0087414 * T2 + T3 / 69699   - T4 / 14712000);
    var F  = norm360( 93.272095  + 483202.0175233  * T - 0.0036539 * T2 - T3 / 3526000 + T4 / 863310000);

    var E  = 1 - 0.002516 * T - 0.0000074 * T2;
    var E2 = E * E;

    var dR = Math.PI / 180;
    var d = D * dR, m = M * dR, mp = Mp * dR, f = F * dR;

    // soma dos 60 termos principais (coef * 1e-6 graus)
    var S = 0;
    S +=  6288774 * Math.sin(mp);
    S +=  1274027 * Math.sin(2*d - mp);
    S +=   658314 * Math.sin(2*d);
    S +=   213618 * Math.sin(2*mp);
    S += -185116 * E * Math.sin(m);
    S += -114332 * Math.sin(2*f);
    S +=    58793 * Math.sin(2*d - 2*mp);
    S +=    57066 * E * Math.sin(2*d - m - mp);
    S +=    53322 * Math.sin(2*d + mp);
    S +=    45758 * E * Math.sin(2*d - m);
    S +=   -40923 * E * Math.sin(m - mp);
    S +=   -34720 * Math.sin(d);
    S +=   -30383 * E * Math.sin(m + mp);
    S +=    15327 * Math.sin(2*d - 2*f);
    S +=   -12528 * Math.sin(mp + 2*f);
    S +=    10980 * Math.sin(mp - 2*f);
    S +=    10675 * Math.sin(4*d - mp);
    S +=    10034 * Math.sin(3*mp);
    S +=     8548 * Math.sin(4*d - 2*mp);
    S +=    -7888 * E * Math.sin(2*d + m - mp);
    S +=    -6766 * E * Math.sin(2*d + m);
    S +=    -5163 * Math.sin(d - mp);
    S +=     4987 * E * Math.sin(d + m);
    S +=     4036 * E * Math.sin(2*d - m + mp);
    S +=     3994 * Math.sin(2*d + 2*mp);
    S +=     3861 * Math.sin(4*d);
    S +=     3665 * Math.sin(2*d - 3*mp);
    S +=    -2689 * E * Math.sin(m - 2*mp);
    S +=    -2602 * Math.sin(2*d - mp + 2*f);
    S +=     2390 * E * Math.sin(2*d - m - 2*mp);
    S +=    -2348 * Math.sin(d + mp);
    S +=     2236 * E2 * Math.sin(2*d - 2*m);
    S +=    -2120 * E * Math.sin(m + 2*mp);
    S +=    -2069 * E2 * Math.sin(2*m);
    S +=     2048 * E2 * Math.sin(2*d - 2*m - mp);
    S +=    -1773 * Math.sin(2*d + mp - 2*f);
    S +=    -1595 * Math.sin(2*d + 2*f);
    S +=     1215 * E * Math.sin(4*d - m - mp);
    S +=    -1110 * Math.sin(2*mp + 2*f);
    S +=     -892 * Math.sin(3*d - mp);
    S +=     -810 * E * Math.sin(2*d + m + mp);
    S +=      759 * E * Math.sin(4*d - m - 2*mp);
    S +=     -713 * E2 * Math.sin(2*m - mp);
    S +=     -700 * E * Math.sin(2*d + 2*m - mp);
    S +=      596 * E * Math.sin(2*d - m + 2*f);
    S +=      549 * Math.sin(4*d + mp);
    S +=      537 * Math.sin(4*mp);
    S +=      520 * E * Math.sin(4*d - m);
    S +=     -487 * Math.sin(d - 2*mp);
    S +=     -399 * E * Math.sin(2*d + m - 2*f);
    S +=     -381 * Math.sin(2*mp - 2*f);
    S +=      351 * E * Math.sin(d + m + mp);
    S +=     -340 * Math.sin(3*d - 2*mp);
    S +=      330 * Math.sin(4*d - 3*mp);
    S +=      327 * E * Math.sin(2*d - m + 2*mp);
    S +=     -323 * E2 * Math.sin(2*m + mp);
    S +=      299 * E * Math.sin(d + m - mp);
    S +=      294 * Math.sin(2*d + 3*mp);

    return norm360(Lp + S / 1000000);
  }

  // -------------------------------------------------------------------------
  // Nodo Norte médio da Lua (Meeus 47.7)
  // -------------------------------------------------------------------------
  function moonNodeLongitude(jd) {
    var T = (jd - 2451545.0) / 36525.0;
    return norm360(
        125.04452
      -  1934.136261 * T
      +     0.0020708 * T * T
      +     T * T * T / 450000
    );
  }

  // -------------------------------------------------------------------------
  // PLANETAS — VSOP87 reduzido
  // Elementos médios + equação de Kepler + correções principais.
  // Método: calcula coordenadas heliocêntricas elíticas da Terra e do
  //         planeta, subtrai, converte para longitude geocêntrica.
  // Precisão suficiente para astrologia (signo/casa/grau).
  // -------------------------------------------------------------------------

  // Elementos orbitais médios (J2000, Meeus/JPL simplificado)
  //   [a, e, i, Ω, ϖ, L0] em UA, grau, grau, grau, grau, grau
  //   [rates] por século juliano
  // Fonte: Standish & Williams, "Keplerian Elements for Approximate
  // Positions of the Major Planets" (JPL)
  var ORBIT = {
    mercury: {
      a:  [0.38709927,  0.00000037],
      e:  [0.20563593,  0.00001906],
      i:  [7.00497902, -0.00594749],
      L:  [252.25032350, 149472.67411175],
      p:  [77.45779628,  0.16047689],      // longitude of perihelion
      O:  [48.33076593, -0.12534081]       // long. ascending node
    },
    venus: {
      a:  [0.72333566,  0.00000390],
      e:  [0.00677672, -0.00004107],
      i:  [3.39467605, -0.0007889],
      L:  [181.97909950, 58517.81538729],
      p:  [131.60246718, 0.00268329],
      O:  [76.67984255, -0.27769418]
    },
    earth: {
      a:  [1.00000261,  0.00000562],
      e:  [0.01671123, -0.00004392],
      i:  [-0.00001531, -0.01294668],
      L:  [100.46457166, 35999.37244981],
      p:  [102.93768193, 0.32327364],
      O:  [0.0, 0.0]
    },
    mars: {
      a:  [1.52371034,  0.00001847],
      e:  [0.09339410,  0.00007882],
      i:  [1.84969142, -0.00813131],
      L:  [-4.55343205, 19140.30268499],
      p:  [-23.94362959, 0.44441088],
      O:  [49.55953891, -0.29257343]
    },
    jupiter: {
      a:  [5.20288700, -0.00011607],
      e:  [0.04838624, -0.00013253],
      i:  [1.30439695, -0.00183714],
      L:  [34.39644051,  3034.74612775],
      p:  [14.72847983,  0.21252668],
      O:  [100.47390909, 0.20469106]
    },
    saturn: {
      a:  [9.53667594, -0.00125060],
      e:  [0.05386179, -0.00050991],
      i:  [2.48599187,  0.00193609],
      L:  [49.95424423,  1222.49362201],
      p:  [92.59887831, -0.41897216],
      O:  [113.66242448, -0.28867794]
    },
    uranus: {
      a:  [19.18916464, -0.00196176],
      e:  [0.04725744,  -0.00004397],
      i:  [0.77263783,  -0.00242939],
      L:  [313.23810451, 428.48202785],
      p:  [170.95427630, 0.40805281],
      O:  [74.01692503,  0.04240589]
    },
    neptune: {
      a:  [30.06992276,  0.00026291],
      e:  [0.00859048,   0.00005105],
      i:  [1.77004347,   0.00035372],
      L:  [-55.12002969, 218.45945325],
      p:  [44.96476227,  -0.32241464],
      O:  [131.78422574, -0.00508664]
    },
    // Plutão — elementos médios (JPL, 3000 BC–3000 AD)
    pluto: {
      a:  [39.48211675, -0.00031596],
      e:  [0.24882730,   0.00005170],
      i:  [17.14001206,  0.00004818],
      L:  [238.92903833, 145.20780515],
      p:  [224.06891629, -0.04062942],
      O:  [110.30393684, -0.01183482]
    }
  };

  function elementsAt(planet, T) {
    var o = ORBIT[planet];
    return {
      a: o.a[0] + o.a[1] * T,
      e: o.e[0] + o.e[1] * T,
      i: o.i[0] + o.i[1] * T,
      L: norm360(o.L[0] + o.L[1] * T),
      p: norm360(o.p[0] + o.p[1] * T),
      O: norm360(o.O[0] + o.O[1] * T)
    };
  }

  // Resolve equação de Kepler: M = E - e*sin(E). Iterativo (Newton).
  function solveKepler(M, e) {
    var Mr = rad(norm360(M));
    if (Mr > Math.PI) Mr -= 2 * Math.PI;
    var E = Mr;
    for (var k = 0; k < 12; k++) {
      var dE = (E - e * Math.sin(E) - Mr) / (1 - e * Math.cos(E));
      E -= dE;
      if (Math.abs(dE) < 1e-12) break;
    }
    return E;
  }

  // Coords heliocêntricas eclípticas retangulares (x, y, z) em UA
  function heliocentricXYZ(planet, T) {
    var E = elementsAt(planet, T);
    var M = norm360(E.L - E.p);
    var ecc = solveKepler(M, E.e);
    // Coord no plano orbital
    var xv = E.a * (Math.cos(ecc) - E.e);
    var yv = E.a * Math.sqrt(1 - E.e * E.e) * Math.sin(ecc);
    // Argumento de latitude na órbita
    var omega = rad(E.p - E.O);       // argumento do periélio
    var Omega = rad(E.O);
    var inc   = rad(E.i);
    var cO = Math.cos(Omega), sO = Math.sin(Omega);
    var ci = Math.cos(inc),   si = Math.sin(inc);
    var cw = Math.cos(omega), sw = Math.sin(omega);
    // Matriz de rotação orbital -> eclíptica J2000
    var x = (cO*cw - sO*sw*ci) * xv + (-cO*sw - sO*cw*ci) * yv;
    var y = (sO*cw + cO*sw*ci) * xv + (-sO*sw + cO*cw*ci) * yv;
    var z = (sw*si)            * xv + (cw*si)             * yv;
    return { x: x, y: y, z: z };
  }

  // Longitude geocêntrica eclíptica de um planeta, em graus
  function planetGeocentricLon(planet, jd) {
    var T = (jd - 2451545.0) / 36525.0;
    var e = heliocentricXYZ("earth", T);
    var p = heliocentricXYZ(planet, T);
    var x = p.x - e.x;
    var y = p.y - e.y;
    return norm360(deg(Math.atan2(y, x)));
  }

  // -------------------------------------------------------------------------
  // PLUTÃO — via elementos orbitais médios + Kepler
  // (mesmo método dos outros planetas; precisão ~0.3–0.5°, suficiente
  //  pra signo/casa/grau astrológico)
  // -------------------------------------------------------------------------
  function plutoLongitude(jd) {
    return planetGeocentricLon("pluto", jd);
  }

  // -------------------------------------------------------------------------
  // QUÍRON — média orbital (período 50.4 anos, epoch J2000)
  // -------------------------------------------------------------------------
  function chironLongitude(jd) {
    // Longitude média em J2000 ≈ 208.5°, taxa ≈ 7.14°/ano
    // Fonte: dados JPL Horizons (aproximação 1ª ordem — ±1°)
    var daysSinceJ2000 = jd - 2451545.0;
    return norm360(208.5 + (360 / 18328.5) * daysSinceJ2000);
  }

  // -------------------------------------------------------------------------
  // API PÚBLICA
  // -------------------------------------------------------------------------
  function calcChart(year, month, day, hourLocal, latitude, longitude, tzOffset) {
    // Aceita hourLocal como número (ex. 5.75) ou hora inteira com minuto
    // passado como fração. O HTML atual passa (hh + mm/60).
    var hourFracLocal = hourLocal;
    var hourFracUTC   = hourFracLocal - tzOffset;
    var utcDay = day;
    while (hourFracUTC < 0)   { hourFracUTC += 24; utcDay--; }
    while (hourFracUTC >= 24) { hourFracUTC -= 24; utcDay++; }

    var jd = julianDay(year, month, utcDay, hourFracUTC);
    var T  = (jd - 2451545.0) / 36525.0;

    var lst = norm360(gmstDeg(jd) + longitude);
    var asc = ascendantDeg(lst, latitude, T);

    return {
      jde: jd,
      T: T,
      asc: asc,
      sol:      sunLongitude(jd),
      lua:      moonLongitude(jd),
      mercurio: planetGeocentricLon("mercury", jd),
      venus:    planetGeocentricLon("venus",   jd),
      marte:    planetGeocentricLon("mars",    jd),
      jupiter:  planetGeocentricLon("jupiter", jd),
      saturno:  planetGeocentricLon("saturn",  jd),
      urano:    planetGeocentricLon("uranus",  jd),
      netuno:   planetGeocentricLon("neptune", jd),
      plutao:   plutoLongitude(jd),
      quiron:   chironLongitude(jd),
      nodo:     moonNodeLongitude(jd)
    };
  }

  // -------------------------------------------------------------------------
  // calcChartIANA — versão que aceita um timezone IANA (ex: "Europe/London",
  // "America/New_York") e resolve o offset (com DST aplicado corretamente)
  // usando a base de dados tzdata embutida no navegador via Intl.
  //
  // Uso:
  //   calcChartIANA(2002, 12, 13, 6, 12, -26.2283, -52.6708, "America/Sao_Paulo")
  //
  // Retorna o mesmo objeto que calcChart.
  //
  // Observação: a base Intl do navegador tem tzdata completa — resolve DST
  // dos EUA, Europa, Austrália etc. automaticamente. Para o Brasil, cuidado:
  // como o HV brasileiro foi abolido em 2019, a tzdata mais recente pode
  // NÃO aplicar DST em datas históricas dependendo da versão do navegador.
  // Para o Brasil, recomenda-se passar o tz numérico direto via calcChart,
  // detectando DST via tabela estática no HTML.
  // -------------------------------------------------------------------------
  function ianaOffsetHours(year, month, day, hour, minute, iana) {
    // Estratégia: formata uma data "neutra" (interpretada como UTC) no fuso
    // IANA e calcula quantas horas de diferença há. Isso nos dá o offset
    // válido para aquela data-hora.
    try {
      var testDate = new Date(Date.UTC(year, month - 1, day, hour, minute, 0));
      var fmt = new Intl.DateTimeFormat("en-US", {
        timeZone: iana,
        year: "numeric", month: "2-digit", day: "2-digit",
        hour: "2-digit", minute: "2-digit", second: "2-digit",
        hour12: false
      });
      var parts = {};
      fmt.formatToParts(testDate).forEach(function (p) { parts[p.type] = p.value; });
      var asLocal = Date.UTC(
        +parts.year, +parts.month - 1, +parts.day,
        +parts.hour === 24 ? 0 : +parts.hour,
        +parts.minute, +parts.second
      );
      var diffMs = asLocal - testDate.getTime();
      return diffMs / 3600000;  // horas
    } catch (e) {
      return 0;
    }
  }

  function calcChartIANA(year, month, day, hour, minute, latitude, longitude, iana) {
    var hourLocal = hour + minute / 60;
    var tz = ianaOffsetHours(year, month, day, hour, minute, iana);
    return calcChart(year, month, day, hourLocal, latitude, longitude, tz);
  }

  // Expõe no escopo global
  if (typeof window !== "undefined") {
    window.ASTRO_ENGINE = {
      calcChart: calcChart,
      calcChartIANA: calcChartIANA,
      ianaOffsetHours: ianaOffsetHours
    };
  }
  if (typeof module !== "undefined" && module.exports) {
    module.exports = {
      calcChart: calcChart,
      calcChartIANA: calcChartIANA,
      ianaOffsetHours: ianaOffsetHours
    };
  }
})();
